    var ADDS = [{"p":"PART 1. 후삼국 통일과 태조 왕건","q":[{"answer":"O","text":"궁예는 국정을 총괄하는 광평성을 비롯한 여러 정치 기구를 마련하여 태봉의 통치 체제를 갖추었다.","exp":"궁예는 후고구려를 세운 뒤 광평성을 중심으로 여러 관서를 두어 통치 조직을 정비하였다. 광평성 설치는 궁예 정권의 대표적 제도 정비로, 미륵신앙을 이용한 가혹한 통치와 함께 태봉의 특징으로 기억한다.","src":"한능검 제77회"},{"answer":"X","text":"왕건은 궁예를 몰아낸 뒤 국정을 총괄하는 광평성을 처음으로 설치하여 통치 체제를 정비하였다.","exp":"설치 주체가 틀렸다. 광평성을 비롯한 여러 관서를 마련한 인물은 궁예이며, 왕건은 궁예를 축출하고 고려를 건국하였다. 광평성 설치의 주체를 왕건으로 뒤바꾼 함정이다."}],"tb":[],"wi":[]},{"p":"PART 4. 문벌 사회의 동요 — 이자겸의 난·묘청의 서경 천도 운동","q":[{"answer":"O","text":"김부식은 관군을 이끌고 서경에서 일어난 묘청의 난을 약 1년 만에 진압하였다.","exp":"김부식은 사대적 개경 문벌을 대표하는 인물로, 관군을 지휘해 서경의 묘청 세력을 진압하였다. 서경 천도·금국 정벌·칭제건원을 주장한 묘청 세력과 정치적으로 정면 대립한 인물임을 함께 기억한다.","src":"한능검 제77회"}],"tb":[],"wi":[]},{"p":"PART 6. 대외 관계 (거란·여진·몽골)","q":[{"answer":"O","text":"고려는 거란의 침입을 부처의 힘으로 물리치려는 염원을 담아 초조대장경을 조판하였다.","exp":"초조대장경은 현종 때 거란의 침입을 계기로 만든 고려 최초의 대장경이다. 뒤에 몽골 침입 때 불타 없어졌고, 이를 대신해 최우 집권기에 다시 새긴 것이 팔만대장경(재조대장경)이라는 점과 구별한다.","src":"한능검 제77회"},{"answer":"X","text":"고려는 거란의 침입을 부처의 힘으로 물리치려는 염원을 담아 팔만대장경을 처음으로 조판하였다.","exp":"대장경 이름이 틀렸다. 거란의 침입 때 만든 것은 초조대장경이며, 팔만대장경(재조대장경)은 몽골의 침입에 맞서 최우 집권기에 강화도에서 새긴 것이다. 침입 대상과 대장경을 뒤바꾼 함정이다."},{"answer":"O","text":"김윤후는 충주성에서 노비 문서를 불태워 사기를 북돋우며 하층민을 이끌고 몽골군을 물리쳤다.","exp":"김윤후는 처인성에서 살리타를 사살한 데 이어 충주성에서도 노비 문서를 불살라 신분 해방을 약속하며 관노비 등과 함께 몽골군을 막아냈다. 처인성(살리타 사살)과 충주성(노비 문서 소각)을 짝지어 정리한다.","src":"한능검 제77회"},{"answer":"X","text":"김윤후가 노비 등 하층민을 이끌고 몽골군을 격퇴한 곳은 박서가 지켜낸 귀주성이었다.","exp":"장소가 틀렸다. 김윤후가 노비 등을 이끌고 몽골군을 물리친 곳은 충주성이며, 귀주성은 박서가 몽골군의 공격을 막아낸 곳이다. 대몽 항쟁의 인물과 장소를 뒤섞은 함정이다."}],"tb":[],"wi":[]},{"p":"PART 9. 고려의 문화 (유학·불교·인쇄·예술)","q":[{"answer":"O","text":"고려에서는 나전 칠기 공예가 발달하여 국화와 넝쿨무늬를 정교하게 새긴 나전 국화 넝쿨무늬 합이 만들어졌다.","exp":"나전 칠기는 자개를 오려 붙여 무늬를 낸 고려의 대표적 공예품으로, 상감 청자와 함께 고려 귀족 문화의 세련미를 보여 준다. 정교한 무늬와 화려한 자개 장식이 특징이다.","src":"한능검 제77회"},{"answer":"X","text":"국화와 넝쿨무늬를 정교하게 새긴 나전 국화 넝쿨무늬 합은 조선 후기를 대표하는 청화 백자 공예품이다.","exp":"종류와 시대가 틀렸다. 나전 국화 넝쿨무늬 합은 자개로 무늬를 낸 고려의 나전 칠기 공예품이며, 조선 후기의 청화 백자와는 재질도 시대도 다르다. 공예품의 갈래를 바꾼 함정이다."},{"answer":"O","text":"안향은 충렬왕 때 원에서 주자의 저서를 들여와 우리나라에 성리학을 처음으로 소개하였다.","exp":"안향은 고려 후기에 원으로부터 성리학을 처음 들여온 인물로, 뒤에 백운동 서원(소수 서원)에 배향되었다. 이후 이제현·이색 등을 거쳐 신진 사대부의 사상적 기반이 되었다는 흐름과 함께 기억한다.","src":"한능검 제77회"},{"answer":"X","text":"우리나라에 성리학을 처음으로 소개한 인물은 만권당에서 원의 학자들과 교류한 이제현이다.","exp":"인물이 틀렸다. 성리학을 처음 소개한 인물은 충렬왕 때의 안향이며, 이제현은 충선왕이 원에 세운 만권당에서 원의 학자들과 교류한 인물이다. 성리학 도입의 선후 인물을 뒤바꾼 함정이다."}],"tb":[],"wi":[]}];
